# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_._build_fiber_proof","kind":"function","src_hash":"9ba28076b72a5ea0","in":{"base":"FiberSpec"},"out":{"base":"ProofTerm"},"spec":{"lhs":"_build_fiber_proof(fib)","rhs":"build a proof term for a single fiber","over":{"base":"FiberSpec"},"name":"_build_fiber_proof_correct","kind":"composition"},"guarantee":"build a proof term for a single fiber","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"Refl","by":"library_axiom"},{"fn":"app","by":"library_axiom"},{"fn":"var","by":"library_axiom"},{"fn":"var","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"be85c1a0be36d99f"}
def _build_fiber_proof(fiber: FiberSpec, ann: VerifiedAnnotation) -> ProofTerm:
    """Build a proof term for a single fiber."""
    s = fiber.proof_strategy
    d = fiber.proof_details
    if s == "refl":
        return Refl(app(var(ann.symbol), var("x")))
    if s in ("library_axiom", "delegation"):
        return LibraryAxiom(
            library=d.get("library", ann.symbol.split(".")[0]),
            axiom_name=d.get("axiom_name", f"{ann.symbol}_{fiber.name}_correct"),
            statement=d.get("statement", f"{ann.symbol} correct on {fiber.name}"),
        )
    if s == "mathlib":
        return MathLibAxiom(
            theorem_name=d.get("theorem_name", ""),
            instantiation={k: var(v) for k, v in d.get("instantiation", {}).items()},
        )
    if s == "z3":
        return Z3Discharge(formula=d.get("formula", "True"), variables=d.get("variables", {}))
    if s == "transport":
        return Transport(
            path_proof=Refl(var("path")),
            source_proof=Refl(app(var(ann.symbol), var("x"))),
        )
    return Assume(statement=f"{ann.symbol} correct on {fiber.name}")


