# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_._build_fiber_cover","kind":"function","src_hash":"016bf0101a591686","in":{"base":"Definition"},"out":{"base":"List[FiberSpec]"},"spec":{"lhs":"_build_fiber_cover(def)","rhs":"build a \u010dech cover from isinstance/type dispatch in the function","over":{"base":"Definition"},"name":"_build_fiber_cover_correct"},"guarantee":"build a \u010dech cover from isinstance/type dispatch in the function","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator_._build_fiber_cover_correct","statement":"Path(_build_fiber_cover(x), build a \u010dech cover from isinstance/type dispatch in the function)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"de6de8114f949c2d"}
def _build_fiber_cover(defn: Definition, library_name: str,
                        input_type: RefinedType, guarantee: str) -> List[FiberSpec]:
    """Build a Čech cover from isinstance/type dispatch in the function."""
    isinstance_preds = _extract_isinstance_predicates(defn.source)
    if not isinstance_preds:
        return []

    fibers: List[FiberSpec] = []
    for pred in isinstance_preds:
        type_name = pred.split(",")[1].strip().rstrip(")")
        fiber_path = PathSpec(
            lhs=f"{defn.name}(x)", rhs=guarantee,
            over=RefinedType(base=type_name, predicate=pred),
            name=f"{defn.name}_{type_name}_case",
        )
        fibers.append(FiberSpec(
            name=type_name.replace(".", "_"),
            predicate=pred,
            path=fiber_path,
            proof_strategy="library_axiom",
            proof_details={
                "library": library_name,
                "axiom_name": f"{defn.qualname}_{type_name}_correct",
                "statement": f"{defn.name} satisfies spec on {type_name} inputs",
            },
            trust="LIBRARY",
        ))
    return fibers


