def _extract_guards(func_node: ast.AST) -> List[str]:
    """Extract guard conditions (if/elif) from a function body."""
    guards: List[str] = []
    for node in ast.walk(func_node):
        if isinstance(node, ast.If):
            try:
                cond = ast.unparse(node.test)
                if len(cond) < 200:
                    guards.append(cond)
            except Exception:
                pass
    return guards


