def _infer_z3_fragment(formula: str) -> str:
    """Infer the Z3 fragment type from a formula."""
    if '*' in formula or '**' in formula:
        return "QF_NIA"
    if any(kw in formula for kw in ("and", "or", "not", "True", "False")):
        return "QF_LIA"
    return "QF_LIA"


