def _ast_call_chain(node: ast.AST) -> List[str]:
    """Extract a chain of function calls from nested call AST."""
    chain: List[str] = []
    current = node
    while isinstance(current, ast.Call):
        try:
            name = ast.unparse(current.func)
            chain.append(name)
        except Exception:
            break
        if current.args:
            current = current.args[0]
        else:
            break
    return chain


