# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | 3938402039d62b97  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_._format_proof_block","kind":"function","src_hash":"748e7570d63e753a","in":{"base":"ProofResult"},"out":{"base":"str"},"spec":{"lhs":"_format_proof_block(r)","rhs":"format a proof result as a compilable annotation block","over":{"base":"ProofResult"},"name":"_format_proof_block_correct"},"guarantee":"format a proof result as a compilable annotation block","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator_._format_proof_block_correct","statement":"Path(_format_proof_block(x), format a proof result as a compilable annotation block)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3938402039d62b97"}
def _format_proof_block(r: ProofResult) -> str:
    """Format a proof result as a compilable annotation block.

    Human-readable box + machine-parseable @cctt_verify JSON line.
    The JSON line is the compilable artifact.
    """
    ann = r.annotation
    if not ann:
        return f"# CCTT: {r.definition.name} — no annotation"

    trust_icon = {"KERNEL": "🟢", "LIBRARY": "🟡", "MATHLIB": "🔵",
                  "INFERRED": "🟠", "ASSUMED": "🔴", "FAILED": "❌", "OPAQUE": "⬛"
                  }.get(ann.trust, "?")
    check = "✓" if ann.compiled else "✗"
    w = 60

    lines = [f"# ╔══ CCTT {'═' * (w - 10)}╗"]

    # Path theorem spec
    spec_str = ann.spec.pretty()
    lines.append(f"# ║ {spec_str:<{w-2}} ║")

    # Type judgment
    type_str = f"{ann.symbol.rsplit('.', 1)[-1]} : {ann.input_type.pretty()} → {ann.output_type.pretty()}"
    if len(type_str) > w - 4:
        type_str = type_str[:w - 7] + "..."
    lines.append(f"# ╠{'═' * w}╣")
    lines.append(f"# ║ {type_str:<{w-2}} ║")

    # Fibers (Čech cover)
    if ann.fibers:
        lines.append(f"# ╠{'═' * w}╣")
        lines.append(f"# ║ {'Čech Cover:':<{w-2}} ║")
        for fiber in ann.fibers[:5]:
            fp = f"  {fiber.name}: {{{fiber.predicate}}} → {fiber.proof_strategy}"
            if len(fp) > w - 4:
                fp = fp[:w - 7] + "..."
            lines.append(f"# ║ {fp:<{w-2}} ║")
        if ann.h1 >= 0:
            h1_str = f"  H¹ = {ann.h1}" + (" (globally proved)" if ann.h1 == 0 else " (obstructed)")
            lines.append(f"# ║ {h1_str:<{w-2}} ║")

    # Cubical paths
    if ann.paths:
        lines.append(f"# ╠{'═' * w}╣")
        for path in ann.paths[:3]:
            ps = path.pretty()
            if len(ps) > w - 4:
                ps = ps[:w - 7] + "..."
            lines.append(f"# ║ {ps:<{w-2}} ║")

    # Trust + verification
    lines.append(f"# ╠{'═' * w}╣")
    status = f" {trust_icon} {ann.trust} | {ann.strategy} | Compiled: {check} | {ann.vhash}"
    if len(status) > w - 2:
        status = status[:w - 5] + "..."
    lines.append(f"# ║{status:<{w}}║")
    lines.append(f"# ╚{'═' * w}╝")

    # Machine-parseable annotation (THE compilable artifact)
    json_str = json.dumps(ann.to_json(), separators=(',', ':'), default=str)
    lines.append(f"# @cctt_verify {json_str}")

    return "\n".join(lines)


