# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.emit_annotated_file","kind":"function","src_hash":"b5a0ed97d1f7acf7","in":{"base":"FileProofReport"},"out":{"base":"str"},"spec":{"lhs":"emit_annotated_file(rep)","rhs":"emit_annotated_file produces the expected output","over":{"base":"FileProofReport"},"name":"emit_annotated_file_correct"},"guarantee":"emit_annotated_file produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.emit_annotated_file_correct","statement":"Path(emit_annotated_file(x), emit_annotated_file produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fcd6a6d2b428ebcf"}
def emit_annotated_file(report: FileProofReport) -> str:
    if not report.results:
        return report.original_source
    insertions: Dict[int, str] = {}
    for r in report.results:
        insertions[r.definition.lineno] = _format_proof_block(r)
    lines = report.original_source.split("\n")
    output: List[str] = []
    for i, line in enumerate(lines, 1):
        if i in insertions:
            output.append(insertions[i])
        output.append(line)
    return "\n".join(output)


