# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.parse_annotations","kind":"function","src_hash":"bcd54c5d3144224f","in":{"base":"str"},"out":{"base":"List[VerifiedAnnotation]"},"spec":{"lhs":"parse_annotations(sou)","rhs":"parse_annotations produces the expected output","over":{"base":"str"},"name":"parse_annotations_correct"},"guarantee":"parse_annotations produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.parse_annotations_correct","statement":"Path(parse_annotations(x), parse_annotations produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"17c0b1e00aba9833"}
def parse_annotations(source: str) -> List[VerifiedAnnotation]:
    anns: List[VerifiedAnnotation] = []
    for line in source.split("\n"):
        m = _CCTT_VERIFY_RE.match(line.strip())
        if m:
            try:
                anns.append(VerifiedAnnotation.from_json(json.loads(m.group(1))))
            except Exception as e:
                logger.warning("parse annotation: %s", e)
    return anns


