# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.verify_annotated_library","kind":"function","src_hash":"6a5e6783bd10ccfe","in":{"base":"Path"},"out":{"base":"Dict[str, List[CompilationResult]]"},"spec":{"lhs":"verify_annotated_library(out)","rhs":"verify_annotated_library produces the expected output","over":{"base":"Path"},"name":"verify_annotated_library_correct"},"guarantee":"verify_annotated_library produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator_.verify_annotated_library_correct","statement":"Path(verify_annotated_library(x), verify_annotated_library produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"66d5028010d850bb"}
def verify_annotated_library(output_dir: Path) -> Dict[str, List[CompilationResult]]:
    results: Dict[str, List[CompilationResult]] = {}
    for py_file in sorted(output_dir.rglob("*.py")):
        rel = str(py_file.relative_to(output_dir))
        file_results = verify_annotated_file(py_file)
        if file_results:
            results[rel] = file_results
    return results


